// Earth Map Component - Dũng
import React, { useEffect, useRef, useState } from 'react';
import './EarthMap.css';

const EarthMap = () => {
  const canvasRef = useRef(null);
  const [zoomLevel, setZoomLevel] = useState(1);
  const [isZooming, setIsZooming] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    drawEarth(ctx, zoomLevel);
  }, [zoomLevel]);

  const drawEarth = (ctx, zoom) => {
    const width = ctx.canvas.width;
    const height = ctx.canvas.height;

    // Clear canvas with space background
    ctx.clearRect(0, 0, width, height);
    const spaceGradient = ctx.createRadialGradient(width/2, height/2, 0, width/2, height/2, width);
    spaceGradient.addColorStop(0, '#0a1628');
    spaceGradient.addColorStop(0.5, '#0d1f3c');
    spaceGradient.addColorStop(1, '#050a14');
    ctx.fillStyle = spaceGradient;
    ctx.fillRect(0, 0, width, height);

    // Draw stars
    for (let i = 0; i < 100; i++) {
      const starX = Math.random() * width;
      const starY = Math.random() * height;
      const starSize = Math.random() * 1.5 + 0.5;
      const starAlpha = Math.random() * 0.8 + 0.2;

      ctx.beginPath();
      ctx.arc(starX, starY, starSize, 0, 2 * Math.PI);
      ctx.fillStyle = `rgba(255, 255, 255, ${starAlpha})`;
      ctx.fill();
    }

    // Draw Earth circle
    const centerX = width / 2;
    const centerY = height / 2;
    const radius = 120 * zoom;

    // Earth shadow/terminator effect
    const shadowGradient = ctx.createRadialGradient(
      centerX - radius * 0.3,
      centerY - radius * 0.3,
      0,
      centerX,
      centerY,
      radius
    );

    // Create realistic Earth gradient
    const earthGradient = ctx.createRadialGradient(
      centerX - radius * 0.4,
      centerY - radius * 0.4,
      0,
      centerX,
      centerY,
      radius
    );
    earthGradient.addColorStop(0, '#4a9eff');
    earthGradient.addColorStop(0.3, '#2e7bc9');
    earthGradient.addColorStop(0.6, '#1e5a9f');
    earthGradient.addColorStop(0.85, '#153d75');
    earthGradient.addColorStop(1, '#0a2444');

    // Draw main Earth sphere
    ctx.beginPath();
    ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
    ctx.fillStyle = earthGradient;
    ctx.fill();

    // Add continent shapes (simplified for realism)
    ctx.save();
    ctx.clip();

    // North America (simplified)
    drawContinent(ctx, centerX - radius * 0.5, centerY - radius * 0.3, radius * 0.3, '#8fbc8f');
    // South America
    drawContinent(ctx, centerX - radius * 0.35, centerY + radius * 0.2, radius * 0.25, '#8fbc8f');
    // Europe
    drawContinent(ctx, centerX + radius * 0.1, centerY - radius * 0.4, radius * 0.15, '#8fbc8f');
    // Africa
    drawContinent(ctx, centerX + radius * 0.15, centerY + radius * 0.05, radius * 0.25, '#8fbc8f');
    // Asia
    drawContinent(ctx, centerX + radius * 0.4, centerY - radius * 0.35, radius * 0.35, '#8fbc8f');
    // Australia
    drawContinent(ctx, centerX + radius * 0.6, centerY + radius * 0.25, radius * 0.15, '#8fbc8f');

    ctx.restore();

    // Add atmospheric glow
    const atmosphereGradient = ctx.createRadialGradient(
      centerX,
      centerY,
      radius,
      centerX,
      centerY,
      radius * 1.08
    );
    atmosphereGradient.addColorStop(0, 'rgba(135, 206, 235, 0.3)');
    atmosphereGradient.addColorStop(0.5, 'rgba(135, 206, 235, 0.15)');
    atmosphereGradient.addColorStop(1, 'rgba(135, 206, 235, 0)');

    ctx.beginPath();
    ctx.arc(centerX, centerY, radius * 1.08, 0, 2 * Math.PI);
    ctx.fillStyle = atmosphereGradient;
    ctx.fill();

    // Add shadow for 3D effect (night side)
    const nightShadow = ctx.createRadialGradient(
      centerX + radius * 0.5,
      centerY - radius * 0.3,
      radius * 0.2,
      centerX,
      centerY,
      radius * 1.1
    );
    nightShadow.addColorStop(0, 'rgba(0, 0, 0, 0)');
    nightShadow.addColorStop(0.6, 'rgba(0, 0, 0, 0.1)');
    nightShadow.addColorStop(0.85, 'rgba(0, 0, 0, 0.3)');
    nightShadow.addColorStop(1, 'rgba(0, 0, 0, 0.5)');

    ctx.beginPath();
    ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
    ctx.fillStyle = nightShadow;
    ctx.fill();

    // Draw Antarctica (more realistic)
    if (zoom >= 1) {
      ctx.save();
      ctx.clip();

      const antarcticaGradient = ctx.createRadialGradient(
        centerX + radius * 0.1,
        centerY + radius * 0.8,
        0,
        centerX + radius * 0.1,
        centerY + radius * 0.7,
        radius * 0.4
      );
      antarcticaGradient.addColorStop(0, '#f5f5f5');
      antarcticaGradient.addColorStop(0.5, '#e8e8e8');
      antarcticaGradient.addColorStop(1, '#d0d0d0');

      ctx.beginPath();
      ctx.ellipse(
        centerX + radius * 0.1,
        centerY + radius * 0.7,
        radius * 0.5,
        radius * 0.25,
        0,
        0,
        2 * Math.PI
      );
      ctx.fillStyle = antarcticaGradient;
      ctx.fill();

      ctx.restore();
    }

    // Draw Palmer Archipelago marker
    if (zoom >= 1.5) {
      const markerX = centerX - 20;
      const markerY = centerY + radius * 0.5;

      // Glow effect for marker
      const markerGlow = ctx.createRadialGradient(
        markerX, markerY, 0,
        markerX, markerY, 20
      );
      markerGlow.addColorStop(0, 'rgba(255, 212, 59, 0.4)');
      markerGlow.addColorStop(1, 'rgba(255, 212, 59, 0)');

      ctx.beginPath();
      ctx.arc(markerX, markerY, 20, 0, 2 * Math.PI);
      ctx.fillStyle = markerGlow;
      ctx.fill();

      // Main marker
      ctx.beginPath();
      ctx.arc(markerX, markerY, 8, 0, 2 * Math.PI);
      ctx.fillStyle = '#FFD43B';
      ctx.fill();
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.stroke();

      // Label with background
      const labelText = 'Palmer Archipelago';
      ctx.font = 'bold 12px Arial';
      const textWidth = ctx.measureText(labelText).width;

      ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
      ctx.fillRect(markerX + 12, markerY - 8, textWidth + 8, 18);

      ctx.fillStyle = '#FFD43B';
      ctx.fillText(labelText, markerX + 16, markerY + 5);
    }

    // Draw 3 islands when zoomed in
    if (zoom >= 2) {
      const islands = [
        { name: 'Biscoe', x: centerX - 30, y: centerY + 20 },
        { name: 'Dream', x: centerX + 10, y: centerY + 30 },
        { name: 'Torgersen', x: centerX + 20, y: centerY + 10 }
      ];

      islands.forEach(island => {
        // Island glow
        const islandGlow = ctx.createRadialGradient(
          island.x, island.y, 0,
          island.x, island.y, 12
        );
        islandGlow.addColorStop(0, 'rgba(255, 212, 59, 0.3)');
        islandGlow.addColorStop(1, 'rgba(255, 212, 59, 0)');

        ctx.beginPath();
        ctx.arc(island.x, island.y, 12, 0, 2 * Math.PI);
        ctx.fillStyle = islandGlow;
        ctx.fill();

        // Main island
        ctx.beginPath();
        ctx.arc(island.x, island.y, 6, 0, 2 * Math.PI);
        ctx.fillStyle = '#A5D8FF';
        ctx.fill();
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 2;
        ctx.stroke();

        // Label with background
        ctx.font = '11px Arial';
        const textWidth = ctx.measureText(island.name).width;

        ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
        ctx.fillRect(island.x + 10, island.y - 8, textWidth + 8, 16);

        ctx.fillStyle = '#FFD43B';
        ctx.fillText(island.name, island.x + 14, island.y + 4);
      });
    }
  };

  const drawContinent = (ctx, x, y, size, color) => {
    const gradient = ctx.createRadialGradient(
      x - size * 0.3, y - size * 0.3, 0,
      x, y, size
    );
    gradient.addColorStop(0, color);
    gradient.addColorStop(0.7, '#6b8e6b');
    gradient.addColorStop(1, '#4a6b4a');

    ctx.beginPath();
    ctx.ellipse(x, y, size, size * 0.7, 0, 0, 2 * Math.PI);
    ctx.fillStyle = gradient;
    ctx.fill();
  };

  const handleZoomIn = () => {
    if (zoomLevel < 3) {
      setIsZooming(true);
      setTimeout(() => {
        setZoomLevel(prev => Math.min(prev + 0.5, 3));
        setIsZooming(false);
      }, 300);
    }
  };

  const handleZoomOut = () => {
    if (zoomLevel > 1) {
      setIsZooming(true);
      setTimeout(() => {
        setZoomLevel(prev => Math.max(prev - 0.5, 1));
        setIsZooming(false);
      }, 300);
    }
  };

  return (
    <div className="earth-map-container">
      <div className="earth-map-wrapper">
        <canvas 
          ref={canvasRef} 
          width={600} 
          height={400}
          className={`earth-canvas ${isZooming ? 'zooming' : ''}`}
        />
        <div className="zoom-controls">
          <button onClick={handleZoomOut} disabled={zoomLevel <= 1}>
            🔍 Zoom Out
          </button>
          <span>Zoom: {zoomLevel}x</span>
          <button onClick={handleZoomIn} disabled={zoomLevel >= 3}>
            🔍 Zoom In
          </button>
        </div>
      </div>
      <p className="earth-map-description">
        📍 Palmer Archipelago, Antarctica - Home to three penguin species
      </p>
    </div>
  );
};

export default EarthMap;
